  1→// scripts/fetch-leaderboard.ts
  2→// Fetches The Bazaar leaderboard data and stores it in Cloudflare D1.
  3→// Run via: npx tsx scripts/fetch-leaderboard.ts
  4→
  5→import { computePlayerProgressFromHistory } from "../shared/player-progress";
  6→
  7→// ---------------------------------------------------------------------------
  8→// Types
  9→// ---------------------------------------------------------------------------
 10→
 11→interface D1Response<T = unknown> {
 12→  success: boolean;
 13→  errors: Array<{ code: number; message: string }>;
 14→  result: Array<{
 15→    success: boolean;
 16→    results: T[];
 17→    meta: Record<string, unknown>;
 18→  }>;
 19→}
 20→
 21→interface AuthTokenRow {
 22→  access_token: string;
 23→  refresh_token: string;
 24→  expires_at: string;
 25→}
 26→
 27→interface RefreshTokenResponse {
 28→  accessToken: string;
 29→  refreshToken: string;
 30→  accessTokenExpiresAt: string;
 31→}
 32→
 33→interface LeaderboardEntry {
 34→  AccountId: string;
 35→  Username: string;
 36→  Position: number;
 37→  Rating: number;
 38→}
 39→
 40→interface LeaderboardResponse {
 41→  seasonId: number;
 42→  totalEntries: number;
 43→  entries: LeaderboardEntry[];
 44→}
 45→
 46→interface D1Statement {
 47→  sql: string;
 48→  params?: unknown[];
 49→}
 50→
 51→// ---------------------------------------------------------------------------
 52→// Configuration
 53→// ---------------------------------------------------------------------------
 54→
 55→const CF_API_TOKEN = requireEnv("CLOUDFLARE_API_TOKEN");
 56→const CF_ACCOUNT_ID = requireEnv("CLOUDFLARE_ACCOUNT_ID");
 57→const D1_DATABASE_ID = requireEnv("D1_DATABASE_ID");
 58→const SEASON_ID_OVERRIDE = process.env.SEASON_ID
 59→  ? Number(process.env.SEASON_ID)
 60→  : null;
 61→
 62→const D1_API_URL = `https://api.cloudflare.com/client/v4/accounts/${CF_ACCOUNT_ID}/d1/database/${D1_DATABASE_ID}/query`;
 63→const GAME_API_BASE = "https://playthebazaar.com/api";
 64→
 65→/** Number of recent seasons to keep in the database. */
 66→const KEEP_SEASONS = 3;
 67→
 68→/** Refresh the access token if it expires within this many minutes. */
 69→const TOKEN_REFRESH_THRESHOLD_MINUTES = 10;
 70→
 71→/** Number of entries to insert per D1 batch statement.
 72→ * D1 HTTP API limits bound params to 100, so we inline values instead.
 73→ * Keep batch small enough for D1's 100KB SQL statement limit. */
 74→const BATCH_SIZE = 200;
 75→
 76→// ---------------------------------------------------------------------------
 77→// Helpers
 78→// ---------------------------------------------------------------------------
 79→
 80→function requireEnv(name: string): string {
 81→  const value = process.env[name];
 82→  if (!value) {
 83→    throw new Error(`Missing required environment variable: ${name}`);
 84→  }
 85→  return value;
 86→}
 87→
 88→function log(message: string): void {
 89→  const ts = new Date().toISOString();
 90→  console.log(`[${ts}] ${message}`);
 91→}
 92→
 93→function isDuplicateColumnError(err: unknown): boolean {
 94→  return (
 95→    err instanceof Error &&
 96→    /duplicate column name: (status|estimated_games|longest_win_streak)/i.test(
 97→      err.message
 98→    )
 99→  );
100→}
101→
102→// ---------------------------------------------------------------------------
103→// D1 HTTP helpers
104→// ---------------------------------------------------------------------------
105→
106→async function queryD1<T = unknown>(
107→  statements: D1Statement | D1Statement[]
108→): Promise<D1Response<T>> {
109→  const body = Array.isArray(statements)
110→    ? JSON.stringify(statements)
111→    : JSON.stringify(statements);
112→
113→  const res = await fetch(D1_API_URL, {
114→    method: "POST",
115→    headers: {
116→      Authorization: `Bearer ${CF_API_TOKEN}`,
117→      "Content-Type": "application/json",
118→    },
119→    body,
120→  });
121→
122→  if (!res.ok) {
123→    const text = await res.text();
124→    throw new Error(`D1 API error (${res.status}): ${text}`);
125→  }
126→
127→  const json = (await res.json()) as D1Response<T>;
128→
129→  if (!json.success) {
130→    throw new Error(`D1 query failed: ${JSON.stringify(json.errors)}`);
131→  }
132→
133→  return json;
134→}
135→
136→// ---------------------------------------------------------------------------
137→// Schema migration
138→// ---------------------------------------------------------------------------
139→
140→async function migrateSchema(): Promise<void> {
141→  log("Running schema migrations...");
142→
143→  // Add status column to snapshots (idempotent: ignore if exists)
144→  try {
145→    await queryD1({
146→      sql: `ALTER TABLE snapshots ADD COLUMN status TEXT NOT NULL DEFAULT 'ready'`,
147→    });
148→    log("Added status column to snapshots.");
149→  } catch (err) {
150→    if (!isDuplicateColumnError(err)) {
151→      throw err;
152→    }
153→  }
154→
155→  await queryD1({
156→    sql: `CREATE TABLE IF NOT EXISTS player_latest (
157→      season_id INTEGER NOT NULL,
158→      account_id TEXT NOT NULL,
159→      username TEXT NOT NULL,
160→      position INTEGER NOT NULL,
161→      rating INTEGER NOT NULL,
162→      fetched_at TEXT NOT NULL,
163→      prev_position_24h INTEGER,
164→      prev_rating_24h INTEGER,
165→      estimated_games INTEGER NOT NULL DEFAULT 0,
166→      longest_win_streak INTEGER NOT NULL DEFAULT 0,
167→      PRIMARY KEY (season_id, account_id)
168→    )`,
169→  });
170→
171→  try {
172→    await queryD1({
173→      sql: `ALTER TABLE player_latest ADD COLUMN estimated_games INTEGER NOT NULL DEFAULT 0`,
174→    });
175→    log("Added estimated_games column to player_latest.");
176→  } catch (err) {
177→    if (!isDuplicateColumnError(err)) {
178→      throw err;
179→    }
180→  }
181→
182→  try {
183→    await queryD1({
184→      sql: `ALTER TABLE player_latest ADD COLUMN longest_win_streak INTEGER NOT NULL DEFAULT 0`,
185→    });
186→    log("Added longest_win_streak column to player_latest.");
187→  } catch (err) {
188→    if (!isDuplicateColumnError(err)) {
189→      throw err;
190→    }
191→  }
192→
193→  await queryD1({
194→    sql: `CREATE INDEX IF NOT EXISTS idx_player_latest_position ON player_latest(season_id, position)`,
195→  });
196→  await queryD1({
197→    sql: `CREATE INDEX IF NOT EXISTS idx_player_latest_username ON player_latest(season_id, username)`,
198→  });
199→
200→  await queryD1({
201→    sql: `CREATE TABLE IF NOT EXISTS player_history (
202→      season_id INTEGER NOT NULL,
203→      account_id TEXT NOT NULL,
204→      snapshot_id INTEGER NOT NULL REFERENCES snapshots(id),
205→      username TEXT NOT NULL,
206→      position INTEGER NOT NULL,
207→      rating INTEGER NOT NULL,
208→      PRIMARY KEY (season_id, account_id, snapshot_id)
209→    )`,
210→  });
211→
212→  log("Schema migrations complete.");
213→}
214→
215→// ---------------------------------------------------------------------------
216→// Auth token management
217→// ---------------------------------------------------------------------------
218→
219→async function getAuthTokens(): Promise<AuthTokenRow> {
220→  log("Reading auth tokens from D1...");
221→
222→  const resp = await queryD1<AuthTokenRow>({
223→    sql: "SELECT access_token, refresh_token, expires_at FROM auth_tokens WHERE id = 1",
224→  });
225→
226→  const rows = resp.result[0]?.results;
227→  if (!rows || rows.length === 0) {
228→    throw new Error(
229→      "No auth tokens found in D1. Seed the auth_tokens table first."
230→    );
231→  }
232→
233→  return rows[0];
234→}
235→
236→function isTokenExpiringSoon(expiresAt: string): boolean {
237→  const expiryTime = new Date(expiresAt).getTime();
238→  const now = Date.now();
239→  const minutesRemaining = (expiryTime - now) / 1000 / 60;
240→
241→  log(
242→    `Token expires at ${expiresAt} (${minutesRemaining.toFixed(1)} min remaining)`
243→  );
244→
245→  return minutesRemaining < TOKEN_REFRESH_THRESHOLD_MINUTES;
246→}
247→
248→async function refreshAuthTokens(
249→  currentAccessToken: string,
250→  currentRefreshToken: string
251→): Promise<AuthTokenRow> {
252→  log("Refreshing auth tokens...");
253→
254→  const res = await fetch(`${GAME_API_BASE}/auth/refreshtokens`, {
255→    method: "POST",
256→    headers: { "Content-Type": "application/json" },
257→    body: JSON.stringify({
258→      accessToken: currentAccessToken,
259→      refreshToken: currentRefreshToken,
260→    }),
261→  });
262→
263→  if (!res.ok) {
264→    const text = await res.text();
265→    throw new Error(`Token refresh failed (${res.status}): ${text}`);
266→  }
267→
268→  const data = (await res.json()) as RefreshTokenResponse;
269→  const now = new Date().toISOString();
270→
271→  log("Saving refreshed tokens to D1...");
272→
273→  await queryD1({
274→    sql: `UPDATE auth_tokens
275→          SET access_token = ?, refresh_token = ?, expires_at = ?, updated_at = ?
276→          WHERE id = 1`,
277→    params: [
278→      data.accessToken,
279→      data.refreshToken,
280→      data.accessTokenExpiresAt,
281→      now,
282→    ],
283→  });
284→
285→  log("Tokens refreshed and saved.");
286→
287→  return {
288→    access_token: data.accessToken,
289→    refresh_token: data.refreshToken,
290→    expires_at: data.accessTokenExpiresAt,
291→  };
292→}
293→
294→async function ensureValidToken(): Promise<string> {
295→  let tokens = await getAuthTokens();
296→
297→  if (isTokenExpiringSoon(tokens.expires_at)) {
298→    tokens = await refreshAuthTokens(
299→      tokens.access_token,
300→      tokens.refresh_token
301→    );
302→  } else {
303→    log("Token is still valid, no refresh needed.");
304→  }
305→
306→  return tokens.access_token;
307→}
308→
309→// ---------------------------------------------------------------------------
310→// Leaderboard fetching
311→// ---------------------------------------------------------------------------
312→
313→async function fetchLeaderboard(
314→  accessToken: string,
315→  seasonId: number
316→): Promise<LeaderboardResponse> {
317→  log(`Fetching leaderboard for season ${seasonId}...`);
318→
319→  const url = `${GAME_API_BASE}/Leaderboards?seasonId=${seasonId}`;
320→
321→  const res = await fetch(url, {
322→    method: "GET",
323→    headers: {
324→      Authorization: `Bearer ${accessToken}`,
325→      "x-clientflavor": "Web",
326→      "x-platform": "Tempo",
327→    },
328→  });
329→
330→  if (!res.ok) {
331→    const text = await res.text();
332→    throw new Error(`Leaderboard API error (${res.status}): ${text}`);
333→  }
334→
335→  const data = (await res.json()) as LeaderboardResponse;
336→
337→  log(
338→    `Fetched ${data.entries.length} entries (totalEntries: ${data.totalEntries})`
339→  );
340→
341→  return data;
342→}
343→
344→// ---------------------------------------------------------------------------
345→// Deduplication
346→// ---------------------------------------------------------------------------
347→
348→function dedupEntries(entries: LeaderboardEntry[]): LeaderboardEntry[] {
349→  const map = new Map<string, LeaderboardEntry>();
350→  for (const entry of entries) {
351→    const existing = map.get(entry.AccountId);
352→    if (!existing || entry.Position < existing.Position) {
353→      map.set(entry.AccountId, entry);
354→    }
355→  }
356→  const deduped = Array.from(map.values());
357→  if (deduped.length < entries.length) {
358→    log(`Deduped ${entries.length} -> ${deduped.length} entries (removed ${entries.length - deduped.length} duplicate account_ids)`);
359→  }
360→  return deduped;
361→}
362→
363→// ---------------------------------------------------------------------------
364→// Data storage
365→// ---------------------------------------------------------------------------
366→
367→async function createSnapshot(
368→  seasonId: number,
369→  totalEntries: number,
370→  fetchedAt: string
371→): Promise<number> {
372→  log("Creating snapshot record...");
373→
374→  const resp = await queryD1<{ id: number }>({
375→    sql: `INSERT INTO snapshots (season_id, fetched_at, total_entries, status)
376→          VALUES (?, ?, ?, 'building')
377→          RETURNING id`,
378→    params: [seasonId, fetchedAt, totalEntries],
379→  });
380→
381→  const snapshotId = resp.result[0]?.results[0]?.id;
382→  if (snapshotId == null) {
383→    throw new Error("Failed to create snapshot: no id returned");
384→  }
385→
386→  log(`Created snapshot #${snapshotId}`);
387→  return snapshotId;
388→}
389→
390→/** Escape a string for safe inline SQL (double single-quotes). */
391→function sqlEscape(value: string): string {
392→  return value.replace(/'/g, "''");
393→}
394→
395→// ---------------------------------------------------------------------------
396→// Derived tables (precomputation)
397→// ---------------------------------------------------------------------------
398→
399→async function computeSnapshotMetricsFromMemory(
400→  snapshotId: number,
401→  entries: LeaderboardEntry[]
402→): Promise<void> {
403→  log("Computing snapshot metrics from memory...");
404→
405→  // entries are already sorted by Position (from API)
406→  const sorted = [...entries].sort((a, b) => a.Position - b.Position);
407→  const top1 = sorted[0]?.Rating ?? null;
408→  const top10 = sorted.length >= 10 ? sorted[9].Rating : sorted[sorted.length - 1]?.Rating ?? null;
409→  const top100 = sorted.length >= 100 ? sorted[99].Rating : sorted[sorted.length - 1]?.Rating ?? null;
410→  const top1000 = sorted.length >= 1000 ? sorted[999].Rating : sorted[sorted.length - 1]?.Rating ?? null;
411→
412→  await queryD1({
413→    sql: `INSERT OR REPLACE INTO snapshot_metrics (snapshot_id, top1_rating, top10_rating, top100_rating, top1000_rating)
414→          VALUES (?, ?, ?, ?, ?)`,
415→    params: [snapshotId, top1, top10, top100, top1000],
416→  });
417→
