822→    log(`Using season ID: ${seasonId}`);
823→
824→    // 3. Fetch leaderboard (retry on empty response — the API is flaky)
825→    const MAX_RETRIES = 3;
826→    const RETRY_DELAY_MS = 5000;
827→    let leaderboard: LeaderboardResponse | null = null;
828→
829→    for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
830→      const result = await fetchLeaderboard(accessToken, seasonId);
831→      if (result.entries.length > 0) {
832→        leaderboard = result;
833→        break;
834→      }
835→      if (attempt < MAX_RETRIES) {
836→        log(`Empty response (attempt ${attempt}/${MAX_RETRIES}), retrying in ${RETRY_DELAY_MS / 1000}s...`);
837→        await new Promise((r) => setTimeout(r, RETRY_DELAY_MS));
838→      } else {
839→        log(`Empty response after ${MAX_RETRIES} attempts.`);
840→      }
841→    }
842→
843→    if (!leaderboard) {
