 348→  }
 349→
 350→  const data = (await res.json()) as LeaderboardResponse;
 351→
 352→  log(
 353→    `Fetched ${data.entries.length} entries (totalEntries: ${data.totalEntries})`
 354→  );
 355→
 356→  return data;
 357→}
