 362→
 363→function dedupEntries(entries: LeaderboardEntry[]): LeaderboardEntry[] {
 364→  const map = new Map<string, LeaderboardEntry>();
 365→  for (const entry of entries) {
 366→    const existing = map.get(entry.AccountId);
 367→    if (!existing || entry.Position < existing.Position) {
 368→      map.set(entry.AccountId, entry);
 369→    }
 370→  }
 371→  const deduped = Array.from(map.values());
 372→  if (deduped.length < entries.length) {
 373→    log(`Deduped ${entries.length} -> ${deduped.length} entries (removed ${entries.length - deduped.length} duplicate account_ids)`);
 374→  }
 375→  return deduped;
 376→}
