 414→async function computeSnapshotMetricsFromMemory(
 415→  snapshotId: number,
 416→  entries: LeaderboardEntry[]
 417→): Promise<void> {
 418→  log("Computing snapshot metrics from memory...");
 419→
 420→  // entries are already sorted by Position (from API)
 421→  const sorted = [...entries].sort((a, b) => a.Position - b.Position);
 422→  const top1 = sorted[0]?.Rating ?? null;
 423→  const top10 = sorted.length >= 10 ? sorted[9].Rating : sorted[sorted.length - 1]?.Rating ?? null;
 424→  const top100 = sorted.length >= 100 ? sorted[99].Rating : sorted[sorted.length - 1]?.Rating ?? null;
 425→  const top1000 = sorted.length >= 1000 ? sorted[999].Rating : sorted[sorted.length - 1]?.Rating ?? null;
 426→
 427→  await queryD1({
 428→    sql: `INSERT OR REPLACE INTO snapshot_metrics (snapshot_id, top1_rating, top10_rating, top100_rating, top1000_rating)
 429→          VALUES (?, ?, ?, ?, ?)`,
 430→    params: [snapshotId, top1, top10, top100, top1000],
 431→  });
 432→
 433→  log("Snapshot metrics saved.");
 434→}
