 455→async function backfillPlayerProgress(seasonId: number): Promise<void> {
 456→  log("Backfilling player progress stats...");
 457→
 458→  const currentResp = await queryD1<{
 459→    account_id: string;
 460→    username: string;
 461→    rating: number;
 462→  }>({
 463→    sql: `SELECT account_id, username, rating FROM player_latest WHERE season_id = ?`,
 464→    params: [seasonId],
 465→  });
 466→  const currentRows = currentResp.result[0]?.results ?? [];
 467→  const activeAccountIds = new Set(currentRows.map((row) => row.account_id));
 468→
 469→  const progressMap = new Map(
 470→    currentRows.map((row) => [
 471→      row.account_id,
 472→      {
 473→        username: row.username,
 474→        lastRating: row.rating,
 475→        estimatedGames: 0,
 476→        currentWinStreak: 0,
 477→        longestWinStreak: 0,
 478→      },
 479→    ])
 480→  );
 481→
 482→  const historyResp = await queryD1<{
 483→    account_id: string;
 484→    username: string;
 485→    rating: number;
 486→  }>({
 487→    sql: `SELECT account_id, username, rating
 488→          FROM player_history
 489→          WHERE season_id = ?
 490→          ORDER BY account_id ASC, snapshot_id ASC`,
 491→    params: [seasonId],
 492→  });
 493→  const historyRows = historyResp.result[0]?.results ?? [];
 494→
 495→  let currentAccountId: string | null = null;
 496→  let currentUsername = "";
 497→  let currentHistory: Array<{ rating: number }> = [];
 498→
 499→  const flushCurrentHistory = () => {
 500→    if (!currentAccountId) {
 501→      return;
 502→    }
 503→
 504→    const progress = computePlayerProgressFromHistory(currentHistory);
 505→    progressMap.set(currentAccountId, {
 506→      username: currentUsername,
 507→      lastRating: currentHistory[currentHistory.length - 1]?.rating ?? null,
 508→      estimatedGames: progress.estimatedGames,
 509→      currentWinStreak: progress.currentWinStreak,
 510→      longestWinStreak: progress.longestWinStreak,
 511→    });
 512→  };
 513→
 514→  for (const row of historyRows) {
 515→    if (row.account_id !== currentAccountId) {
 516→      flushCurrentHistory();
 517→      currentAccountId = row.account_id;
 518→      currentUsername = row.username;
 519→      currentHistory = [{ rating: row.rating }];
 520→      continue;
 521→    }
 522→
 523→    currentUsername = row.username;
 524→    currentHistory.push({ rating: row.rating });
 525→  }
 526→  flushCurrentHistory();
 527→
 528→  const progressEntries = Array.from(progressMap.entries());
 529→  for (let i = 0; i < progressEntries.length; i += BATCH_SIZE) {
 530→    const batch = progressEntries.slice(i, i + BATCH_SIZE);
 531→    const values = batch
 532→      .map(
 533→        ([accountId, progress]) =>
 534→          `(${seasonId}, '${sqlEscape(accountId)}', '${sqlEscape(progress.username)}', ${progress.lastRating ?? "NULL"}, ${progress.estimatedGames}, ${progress.currentWinStreak}, ${progress.longestWinStreak})`
 535→      )
 536→      .join(", ");
 537→    await queryD1({
 538→      sql: `INSERT OR REPLACE INTO player_progress
 539→            (season_id, account_id, username, last_rating, estimated_games, current_win_streak, longest_win_streak)
 540→            VALUES ${values}`,
 541→    });
 542→  }
 543→
 544→  const activeProgressEntries = progressEntries.filter(([accountId]) =>
 545→    activeAccountIds.has(accountId)
 546→  );
 547→  for (let i = 0; i < activeProgressEntries.length; i += BATCH_SIZE) {
 548→    const batch = activeProgressEntries.slice(i, i + BATCH_SIZE);
 549→    const ids: string[] = [];
 550→    const gameCases: string[] = [];
 551→    const currentStreakCases: string[] = [];
 552→    const longestStreakCases: string[] = [];
 553→
 554→    for (const [accountId, progress] of batch) {
 555→      const escapedId = sqlEscape(accountId);
 556→      ids.push(`'${escapedId}'`);
 557→      gameCases.push(`WHEN '${escapedId}' THEN ${progress.estimatedGames}`);
 558→      currentStreakCases.push(
 559→        `WHEN '${escapedId}' THEN ${progress.currentWinStreak}`
 560→      );
 561→      longestStreakCases.push(
 562→        `WHEN '${escapedId}' THEN ${progress.longestWinStreak}`
 563→      );
 564→    }
 565→
 566→    await queryD1({
 567→      sql: `UPDATE player_latest
 568→            SET estimated_games = CASE account_id ${gameCases.join(" ")} ELSE estimated_games END,
 569→                current_win_streak = CASE account_id ${currentStreakCases.join(" ")} ELSE current_win_streak END,
 570→                longest_win_streak = CASE account_id ${longestStreakCases.join(" ")} ELSE longest_win_streak END
 571→            WHERE season_id = ? AND account_id IN (${ids.join(", ")})`,
 572→      params: [seasonId],
 573→    });
 574→  }
 575→
 576→  log(`  Backfilled progress for ${progressEntries.length} players.`);
 577→}
 578→
 579→async function syncPlayerTables(
 580→  snapshotId: number,
 581→  seasonId: number,
 582→  fetchedAt: string,
 583→  entries: LeaderboardEntry[]
 584→): Promise<{ needsPlayerProgressBackfill: boolean }> {
 585→  log("Syncing player tables...");
 586→
 587→  // 1. Read current player_latest for this season
 588→  const prevResp = await queryD1<PlayerLatestRow>({
 589→    sql: `SELECT account_id, username, position, rating, estimated_games, current_win_streak, longest_win_streak
 590→          FROM player_latest
 591→          WHERE season_id = ?`,
 592→    params: [seasonId],
 593→  });
 594→  const prevRows = prevResp.result[0]?.results ?? [];
 595→  const prevMap = new Map<string, PlayerLatestRow>();
 596→  for (const row of prevRows) {
 597→    prevMap.set(row.account_id, row);
 598→  }
 599→
 600→  const progressResp = await queryD1<PlayerProgressRow>({
 601→    sql: `SELECT account_id, username, last_rating, estimated_games, current_win_streak, longest_win_streak
 602→          FROM player_progress
 603→          WHERE season_id = ?`,
 604→    params: [seasonId],
 605→  });
 606→  const progressRows = progressResp.result[0]?.results ?? [];
 607→  const progressMap = new Map<string, PlayerProgressRow>();
 608→  for (const row of progressRows) {
 609→    progressMap.set(row.account_id, row);
 610→  }
 611→  const needsPlayerProgressBackfill = prevRows.some(
 612→    (row) => !progressMap.has(row.account_id)
 613→  );
 614→
 615→  // 2. Find 24h-ago baseline snapshot (or earliest snapshot if season < 24h old)
 616→  const baselineResp = await queryD1<{ id: number }>({
 617→    sql: `SELECT id FROM snapshots
 618→          WHERE season_id = ? AND status = 'ready'
 619→            AND total_entries > 1
 620→            AND fetched_at <= datetime(?, '-1 day')
 621→          ORDER BY fetched_at DESC LIMIT 1`,
 622→    params: [seasonId, fetchedAt],
 623→  });
 624→  let baselineSnapshotId = baselineResp.result[0]?.results[0]?.id ?? null;
 625→
 626→  // If no 24h-ago snapshot exists (season < 24h old), use the earliest snapshot
 627→  if (!baselineSnapshotId) {
 628→    const earliestResp = await queryD1<{ id: number }>({
 629→      sql: `SELECT id FROM snapshots
 630→            WHERE season_id = ? AND status = 'ready'
 631→              AND total_entries > 1
 632→            ORDER BY fetched_at ASC LIMIT 1`,
 633→      params: [seasonId],
 634→    });
 635→    baselineSnapshotId = earliestResp.result[0]?.results[0]?.id ?? null;
 636→  }
 637→
 638→  // 3. Detect changes and build batches
 639→  const changed: LeaderboardEntry[] = [];
 640→  const currentAccountIds = new Set<string>();
 641→
 642→  for (const entry of entries) {
 643→    currentAccountIds.add(entry.AccountId);
 644→    const prev = prevMap.get(entry.AccountId);
 645→    if (
 646→      !prev ||
 647→      prev.rating !== entry.Rating ||
 648→      prev.position !== entry.Position ||
 649→      prev.username !== entry.Username
 650→    ) {
 651→      changed.push(entry);
 652→    }
 653→  }
 654→
 655→  log(`  ${changed.length} changed/new out of ${entries.length} total`);
 656→
 657→  // 4. Batch INSERT changed rows to player_history
 658→  if (changed.length > 0) {
 659→    for (let i = 0; i < changed.length; i += BATCH_SIZE) {
 660→      const batch = changed.slice(i, i + BATCH_SIZE);
 661→      const values = batch
 662→        .map(
 663→          (e) =>
 664→            `(${seasonId}, '${sqlEscape(e.AccountId)}', ${snapshotId}, '${sqlEscape(e.Username)}', ${e.Position}, ${e.Rating})`
 665→        )
 666→        .join(", ");
 667→
 668→      await queryD1({
 669→        sql: `INSERT OR IGNORE INTO player_history (season_id, account_id, snapshot_id, username, position, rating) VALUES ${values}`,
 670→      });
 671→    }
 672→    log(`  Inserted ${changed.length} rows to player_history`);
 673→  }
 674→
 675→  // 5. Compute 24h baselines for ALL players and UPSERT/UPDATE player_latest
 676→  // Build baseline map for ALL players (not just changed ones)
 677→  const deltaMap = new Map<string, { position: number; rating: number }>();
 678→
 679→  if (baselineSnapshotId) {
 680→    // Query baselines from player_history for ALL players in batches
 681→    for (let i = 0; i < entries.length; i += BATCH_SIZE) {
 682→      const batch = entries.slice(i, i + BATCH_SIZE);
 683→      const accountIds = batch.map((e) => `'${sqlEscape(e.AccountId)}'`).join(", ");
 684→      const deltaResp = await queryD1<{
 685→        account_id: string;
 686→        position: number;
 687→        rating: number;
 688→      }>({
 689→        sql: `SELECT h.account_id, h.position, h.rating
 690→              FROM player_history h
 691→              WHERE h.season_id = ? AND h.account_id IN (${accountIds})
 692→                AND h.snapshot_id <= ?
 693→              ORDER BY h.snapshot_id DESC`,
 694→        params: [seasonId, baselineSnapshotId],
 695→      });
 696→
 697→      // Take only the latest row per account_id (results are ordered by snapshot_id DESC)
 698→      const rows = deltaResp.result[0]?.results ?? [];
 699→      for (const row of rows) {
 700→        if (!deltaMap.has(row.account_id)) {
 701→          deltaMap.set(row.account_id, {
 702→            position: row.position,
 703→            rating: row.rating,
 704→          });
 705→        }
 706→      }
 707→    }
 708→
 709→    // For players with no history entry at/before baseline, use their
 710→    // current player_latest values (they've been unchanged since before baseline)
 711→    for (const entry of entries) {
 712→      if (!deltaMap.has(entry.AccountId)) {
 713→        const prev = prevMap.get(entry.AccountId);
 714→        if (prev) {
 715→          deltaMap.set(entry.AccountId, {
 716→            position: prev.position,
 717→            rating: prev.rating,
 718→          });
 719→        }
 720→      }
 721→    }
 722→  }
 723→
 724→  // 5a. UPSERT changed players to player_latest (updates all fields + baselines)
 725→  if (changed.length > 0) {
 726→    for (let i = 0; i < changed.length; i += BATCH_SIZE) {
 727→      const batch = changed.slice(i, i + BATCH_SIZE);
 728→      const computedBatch = batch.map((e) => {
 729→        const delta = deltaMap.get(e.AccountId);
 730→        const prev = progressMap.get(e.AccountId);
 731→        const progress = advancePlayerProgress(
 732→          prev
 733→            ? {
 734→                estimatedGames: prev.estimated_games,
 735→                currentWinStreak: prev.current_win_streak,
 736→                longestWinStreak: prev.longest_win_streak,
 737→              }
 738→            : {
 739→                estimatedGames: 0,
 740→                currentWinStreak: 0,
 741→                longestWinStreak: 0,
 742→              },
 743→          prev?.last_rating ?? null,
 744→          e.Rating
 745→        );
 746→        return { entry: e, delta, progress };
 747→      });
 748→
 749→      const latestValues = computedBatch
 750→        .map(({ entry, delta, progress }) => {
 751→          const e = entry;
 752→          const prevPos = delta ? delta.position : "NULL";
 753→          const prevRat = delta ? delta.rating : "NULL";
 754→          return `(${seasonId}, '${sqlEscape(e.AccountId)}', '${sqlEscape(e.Username)}', ${e.Position}, ${e.Rating}, '${sqlEscape(fetchedAt)}', ${prevPos}, ${prevRat}, ${progress.estimatedGames}, ${progress.currentWinStreak}, ${progress.longestWinStreak})`;
 755→        })
 756→        .join(", ");
 757→
 758→      await queryD1({
 759→        sql: `INSERT OR REPLACE INTO player_latest (season_id, account_id, username, position, rating, fetched_at, prev_position_24h, prev_rating_24h, estimated_games, current_win_streak, longest_win_streak) VALUES ${latestValues}`,
 760→      });
 761→
 762→      const progressValues = computedBatch
 763→        .map(({ entry, progress }) => {
 764→          const e = entry;
 765→          progressMap.set(e.AccountId, {
 766→            account_id: e.AccountId,
 767→            username: e.Username,
 768→            last_rating: e.Rating,
 769→            estimated_games: progress.estimatedGames,
 770→            current_win_streak: progress.currentWinStreak,
 771→            longest_win_streak: progress.longestWinStreak,
 772→          });
 773→          return `(${seasonId}, '${sqlEscape(e.AccountId)}', '${sqlEscape(e.Username)}', ${e.Rating}, ${progress.estimatedGames}, ${progress.currentWinStreak}, ${progress.longestWinStreak})`;
 774→        })
 775→        .join(", ");
 776→
 777→      await queryD1({
 778→        sql: `INSERT OR REPLACE INTO player_progress
 779→              (season_id, account_id, username, last_rating, estimated_games, current_win_streak, longest_win_streak)
 780→              VALUES ${progressValues}`,
 781→      });
 782→    }
 783→    log(`  Upserted ${changed.length} changed rows to player_latest`);
 784→    log(`  Upserted ${changed.length} changed rows to player_progress`);
 785→  }
 786→
 787→  // 5b. UPDATE baselines for unchanged players
 788→  // These players already exist in player_latest but their prev_*_24h may be stale/NULL
 789→  if (baselineSnapshotId) {
 790→    const changedIds = new Set(changed.map((c) => c.AccountId));
 791→    const unchanged = entries.filter((e) => !changedIds.has(e.AccountId));
 792→    let updatedCount = 0;
 793→    for (let i = 0; i < unchanged.length; i += BATCH_SIZE) {
 794→      const batch = unchanged.slice(i, i + BATCH_SIZE);
 795→      // Use CASE expressions to update multiple rows in one query
 796→      const posCases: string[] = [];
 797→      const ratCases: string[] = [];
 798→      const ids: string[] = [];
 799→      for (const e of batch) {
 800→        const delta = deltaMap.get(e.AccountId);
 801→        if (delta) {
 802→          const escapedId = sqlEscape(e.AccountId);
 803→          ids.push(`'${escapedId}'`);
 804→          posCases.push(`WHEN '${escapedId}' THEN ${delta.position}`);
 805→          ratCases.push(`WHEN '${escapedId}' THEN ${delta.rating}`);
 806→        }
 807→      }
 808→      if (ids.length > 0) {
 809→        await queryD1({
 810→          sql: `UPDATE player_latest
 811→                SET prev_position_24h = CASE account_id ${posCases.join(" ")} ELSE prev_position_24h END,
 812→                    prev_rating_24h = CASE account_id ${ratCases.join(" ")} ELSE prev_rating_24h END
 813→                WHERE season_id = ? AND account_id IN (${ids.join(", ")})`,
 814→          params: [seasonId],
 815→        });
 816→        updatedCount += ids.length;
 817→      }
 818→    }
 819→    if (updatedCount > 0) {
 820→      log(`  Updated baselines for ${updatedCount} unchanged players`);
 821→    }
 822→  }
 823→
 824→  // 6. Delete delisted players
 825→  const delistedIds: string[] = [];
 826→  for (const accountId of prevMap.keys()) {
 827→    if (!currentAccountIds.has(accountId)) {
 828→      delistedIds.push(accountId);
 829→    }
 830→  }
 831→  if (delistedIds.length > 0) {
 832→    for (let i = 0; i < delistedIds.length; i += BATCH_SIZE) {
 833→      const batch = delistedIds.slice(i, i + BATCH_SIZE);
 834→      const ids = batch.map((id) => `'${sqlEscape(id)}'`).join(", ");
 835→      await queryD1({
 836→        sql: `DELETE FROM player_latest WHERE season_id = ? AND account_id IN (${ids})`,
 837→        params: [seasonId],
 838→      });
 839→    }
 840→    log(`  Deleted ${delistedIds.length} delisted players from player_latest`);
 841→  }
 842→
 843→  log("Player tables synced.");
 844→  return { needsPlayerProgressBackfill };
 845→}
