 866→async function detectLatestSeason(accessToken: string): Promise<number> {
 867→  log("Auto-detecting latest season...");
 868→
 869→  let seasonId = await getKnownMaxSeason();
 870→  log(`Last known season in DB: ${seasonId}`);
 871→
 872→  // Probe upward: if current season has entries, try the next one
 873→  while (true) {
 874→    const probe = await fetchLeaderboard(accessToken, seasonId + 1);
 875→    if (probe.totalEntries > 0) {
 876→      seasonId = seasonId + 1;
 877→      log(`Season ${seasonId} has ${probe.totalEntries} entries, trying next...`);
 878→    } else {
 879→      break;
 880→    }
 881→  }
 882→
 883→  log(`Latest season detected: ${seasonId}`);
 884→  return seasonId;
 885→}
