 891→async function cleanupOldSeasons(): Promise<void> {
 892→  const resp = await queryD1<{ season_id: number }>({
 893→    sql: "SELECT DISTINCT season_id FROM snapshots ORDER BY season_id DESC",
 894→  });
 895→
 896→  const allSeasons = resp.result[0]?.results.map((r) => r.season_id) ?? [];
 897→
 898→  if (allSeasons.length <= KEEP_SEASONS) {
 899→    log(`Only ${allSeasons.length} season(s) in DB, no cleanup needed.`);
 900→    return;
 901→  }
 902→
 903→  const seasonsToDelete = allSeasons.slice(KEEP_SEASONS);
 904→  log(`Cleaning up old seasons: ${seasonsToDelete.join(", ")}`);
 905→
 906→  const placeholders = seasonsToDelete.map(() => "?").join(", ");
 907→
 908→  // Delete derived tables, then snapshots
 909→  const snapshotFilter = `SELECT id FROM snapshots WHERE season_id IN (${placeholders})`;
 910→  await queryD1({
 911→    sql: `DELETE FROM snapshot_metrics WHERE snapshot_id IN (${snapshotFilter})`,
 912→    params: seasonsToDelete,
 913→  });
 914→  await queryD1({
 915→    sql: `DELETE FROM player_history WHERE season_id IN (${placeholders})`,
 916→    params: seasonsToDelete,
 917→  });
 918→  await queryD1({
 919→    sql: `DELETE FROM player_latest WHERE season_id IN (${placeholders})`,
 920→    params: seasonsToDelete,
 921→  });
 922→  await queryD1({
 923→    sql: `DELETE FROM player_progress WHERE season_id IN (${placeholders})`,
 924→    params: seasonsToDelete,
 925→  });
 926→  await queryD1({
 927→    sql: `DELETE FROM snapshots WHERE season_id IN (${placeholders})`,
 928→    params: seasonsToDelete,
 929→  });
 930→
 931→  log(`Deleted data for season(s): ${seasonsToDelete.join(", ")}`);
 932→}
