 938→async function proactiveRefresh(): Promise<void> {
 939→  try {
 940→    log("Proactively refreshing tokens for next run...");
 941→    const tokens = await getAuthTokens();
 942→    await refreshAuthTokens(tokens.access_token, tokens.refresh_token);
 943→  } catch (err) {
 944→    // Don't let refresh failure mask the original error
 945→    log(`Warning: proactive token refresh failed: ${err}`);
 946→  }
 947→}
 948→
 949→async function main(): Promise<void> {
 950→  log("=== Bazaar Leaderboard Fetch Start ===");
 951→
 952→  try {
 953→    // 0. Run migrations
 954→    await migrateSchema();
 955→
 956→    // 1. Get a valid access token (refresh if needed)
 957→    const accessToken = await ensureValidToken();
 958→
 959→    // 2. Determine which season to fetch
 960→    const seasonId =
 961→      SEASON_ID_OVERRIDE ?? (await detectLatestSeason(accessToken));
 962→    log(`Using season ID: ${seasonId}`);
 963→
 964→    // 3. Fetch leaderboard (retry on empty response — the API is flaky)
 965→    const MAX_RETRIES = 3;
 966→    const RETRY_DELAY_MS = 5000;
 967→    let leaderboard: LeaderboardResponse | null = null;
 968→
 969→    for (let attempt = 1; attempt <= MAX_RETRIES; attempt++) {
 970→      const result = await fetchLeaderboard(accessToken, seasonId);
 971→      if (result.entries.length > 0) {
 972→        leaderboard = result;
 973→        break;
 974→      }
 975→      if (attempt < MAX_RETRIES) {
 976→        log(`Empty response (attempt ${attempt}/${MAX_RETRIES}), retrying in ${RETRY_DELAY_MS / 1000}s...`);
 977→        await new Promise((r) => setTimeout(r, RETRY_DELAY_MS));
 978→      } else {
 979→        log(`Empty response after ${MAX_RETRIES} attempts.`);
 980→      }
 981→    }
 982→
 983→    if (!leaderboard) {
 984→      throw new Error(`Leaderboard API returned empty data after ${MAX_RETRIES} attempts`);
 985→    }
 986→
 987→    // 4. Dedup by account_id
 988→    const entries = dedupEntries(leaderboard.entries);
 989→
 990→    // 5. Create snapshot (status=building)
 991→    const fetchedAt = new Date().toISOString();
 992→    const snapshotId = await createSnapshot(
 993→      seasonId,
 994→      leaderboard.totalEntries,
 995→      fetchedAt
 996→    );
 997→
 998→    // 6. Compute metrics from memory
 999→    await computeSnapshotMetricsFromMemory(snapshotId, entries);
1000→
1001→    // 7. Sync player tables
1002→    const { needsPlayerProgressBackfill } = await syncPlayerTables(
1003→      snapshotId,
1004→      seasonId,
1005→      fetchedAt,
1006→      entries
1007→    );
1008→
1009→    // 8. Backfill progress once for seasons that have active rows but no
1010→    // persisted player_progress state yet.
1011→    if (needsPlayerProgressBackfill) {
1012→      await backfillPlayerProgress(seasonId);
1013→    }
1014→
1015→    // 9. Mark snapshot ready
1016→    await markSnapshotReady(snapshotId);
1017→
1018→    // 10. Cleanup old seasons
1019→    await cleanupOldSeasons();
1020→
1021→    log("=== Bazaar Leaderboard Fetch Complete ===");
1022→  } finally {
1023→    // Always refresh token for next run, even if main flow failed.
1024→    // Access token expires in ~15 min but CI runs every 30 min,
1025→    // so always refresh to keep the refresh token chain alive.
1026→    await proactiveRefresh();
1027→  }
1028→}
1029→
1030→main().catch((err: unknown) => {
1031→  console.error("Fatal error:", err);
1032→  process.exit(1);
1033→});
