16→export const onRequestPost: PagesFunction<Env> = async (context) => {
17→  const db = context.env.DB;
18→  const adminSecret = context.env.ADMIN_SECRET;
19→
20→  // Verify admin authorization
21→  if (!adminSecret) {
22→    return Response.json(
23→      { error: "ADMIN_SECRET is not configured" },
24→      { status: 500, headers: corsHeaders }
25→    );
26→  }
27→
28→  const authHeader = context.request.headers.get("Authorization");
29→  if (!authHeader || authHeader !== `Bearer ${adminSecret}`) {
30→    return Response.json(
31→      { error: "Unauthorized" },
32→      { status: 401, headers: corsHeaders }
33→    );
34→  }
35→
36→  try {
37→    const body = await context.request.json<{
38→      accessToken: string;
39→      refreshToken: string;
40→      expiresAt: string;
41→    }>();
42→
43→    if (!body.accessToken || !body.refreshToken || !body.expiresAt) {
44→      return Response.json(
45→        {
46→          error:
47→            "Missing required fields: accessToken, refreshToken, expiresAt",
48→        },
49→        { status: 400, headers: corsHeaders }
50→      );
51→    }
52→
53→    const now = new Date().toISOString();
54→
55→    await db
