58→         VALUES (1, ?, ?, ?, ?)`
59→      )
60→      .bind(body.accessToken, body.refreshToken, body.expiresAt, now)
61→      .run();
62→
63→    return Response.json(
64→      { success: true, updatedAt: now },
65→      { headers: corsHeaders }
66→    );
67→  } catch (err) {
68→    const message = err instanceof Error ? err.message : "Unknown error";
69→    return Response.json(
70→      { error: message },
71→      { status: 500, headers: corsHeaders }
72→    );
