  1→/**
  2→ * One-off script: import historical rating data from bazaar.mrmao.life
  3→ * for the top N players into our D1 database.
  4→ *
  5→ * Only imports data BEFORE our automated collection started (Feb 24 17:33 UTC).
  6→ * Subsamples to 30-minute intervals to reduce write volume.
  7→ *
  8→ * Usage: npx tsx scripts/import-mrmao-history.ts
  9→ */
 10→
 11→const CF_ACCOUNT_ID = "111a703d91e4f2cd124b0bfb72ef836b";
 12→const CF_API_TOKEN = "REDACTED";
 13→const D1_DATABASE_ID = "0d26e1f3-d0ee-41f5-bd8b-f1f04b72fa99";
 14→const SEASON_ID = 12;
 15→const CUTOFF = "2026-02-24T17:30:00Z"; // before our first real snapshot
 16→const SAMPLE_INTERVAL_MS = 30 * 60 * 1000; // 30 minutes
 17→const BATCH_SIZE = 20; // SQLite limit: 100 params, 5 params per row → max 20
 18→
 19→interface MrmaoPoint {
 20→  timestamp: string; // "2026-02-11 23:11:16"
 21→  rating: number;
 22→  position: number;
 23→}
 24→
 25→interface SnapshotEntry {
 26→  username: string;
 27→  rating: number;
 28→  position: number;
 29→}
 30→
 31→async function fetchMrmaoHistory(
 32→  username: string
 33→): Promise<MrmaoPoint[]> {
 34→  const url = `https://bazaar.mrmao.life/api/rating-history?username=${encodeURIComponent(username)}&seasonId=${SEASON_ID}`;
 35→  const res = await fetch(url);
 36→  if (!res.ok) throw new Error(`Failed to fetch ${username}: ${res.status}`);
 37→  return res.json();
 38→}
 39→
 40→async function fetchTopPlayers(count: number): Promise<string[]> {
 41→  const res = await fetch(
 42→    `https://bazaar-leaderboard.pages.dev/api/leaderboard?seasonId=${SEASON_ID}&limit=${count}`
 43→  );
 44→  if (!res.ok) throw new Error(`Failed to fetch leaderboard: ${res.status}`);
 45→  const data = await res.json();
 46→  return data.entries.map((e: { username: string }) => e.username);
 47→}
 48→
 49→function roundToInterval(ts: string): string {
 50→  // mrmao format: "2026-02-11 23:11:16" → ISO
 51→  const d = new Date(ts.replace(" ", "T") + "Z");
 52→  const rounded = new Date(
 53→    Math.round(d.getTime() / SAMPLE_INTERVAL_MS) * SAMPLE_INTERVAL_MS
 54→  );
 55→  return rounded.toISOString();
 56→}
 57→
 58→async function d1Query(sql: string, params: unknown[] = []) {
 59→  const res = await fetch(
 60→    `https://api.cloudflare.com/client/v4/accounts/${CF_ACCOUNT_ID}/d1/database/${D1_DATABASE_ID}/query`,
 61→    {
 62→      method: "POST",
 63→      headers: {
 64→        Authorization: `Bearer ${CF_API_TOKEN}`,
 65→        "Content-Type": "application/json",
 66→      },
 67→      body: JSON.stringify({ sql, params }),
 68→    }
 69→  );
 70→  if (!res.ok) {
 71→    const text = await res.text();
 72→    throw new Error(`D1 query failed: ${res.status} ${text}`);
 73→  }
 74→  return res.json();
 75→}
 76→
 77→async function d1InsertEntries(
 78→  snapshotId: number,
 79→  entries: SnapshotEntry[]
 80→) {
 81→  // Use multi-row INSERT to reduce API calls
 82→  // account_id is NOT NULL in schema but mrmao doesn't provide it — use empty string
 83→  const placeholders = entries.map(() => "(?, ?, ?, ?, ?)").join(", ");
 84→  const params: unknown[] = [];
 85→  for (const e of entries) {
 86→    params.push(snapshotId, "", e.position, e.username, e.rating);
 87→  }
 88→  const sql = `INSERT OR IGNORE INTO entries (snapshot_id, account_id, position, username, rating) VALUES ${placeholders}`;
 89→  return d1Query(sql, params);
 90→}
 91→
 92→async function main() {
 93→  // 1. Get top 100 players + pengx17
 94→  console.log("Fetching top 100 players...");
 95→  const topPlayers = await fetchTopPlayers(100);
 96→  const allPlayers = [...new Set([...topPlayers, "pengx17"])];
 97→  console.log(`Will import data for ${allPlayers.length} players`);
 98→
 99→  // 2. Fetch all histories from mrmao (with concurrency limit)
100→  console.log("Fetching histories from mrmao...");
101→  const playerHistories = new Map<string, MrmaoPoint[]>();
102→  const CONCURRENCY = 10;
103→
104→  for (let i = 0; i < allPlayers.length; i += CONCURRENCY) {
105→    const batch = allPlayers.slice(i, i + CONCURRENCY);
106→    const results = await Promise.allSettled(
107→      batch.map((u) => fetchMrmaoHistory(u))
108→    );
109→    for (let j = 0; j < batch.length; j++) {
110→      const result = results[j];
111→      if (result.status === "fulfilled" && result.value.length > 0) {
112→        playerHistories.set(batch[j], result.value);
113→      } else {
114→        const reason =
115→          result.status === "rejected" ? result.reason : "no data";
116→        console.warn(`  Skip ${batch[j]}: ${reason}`);
117→      }
118→    }
119→    console.log(
120→      `  Fetched ${Math.min(i + CONCURRENCY, allPlayers.length)}/${allPlayers.length}`
121→    );
122→  }
123→
124→  // 3. Build snapshot map: rounded timestamp → entries
125→  console.log("Building snapshot map...");
126→  const cutoffTime = new Date(CUTOFF).getTime();
127→  const snapshotMap = new Map<string, SnapshotEntry[]>();
128→
129→  for (const [username, history] of playerHistories) {
130→    // Subsample: keep one point per 30-min interval, before cutoff
131→    const seen = new Set<string>();
132→    for (const point of history) {
133→      const isoTime = new Date(point.timestamp.replace(" ", "T") + "Z");
134→      if (isoTime.getTime() >= cutoffTime) continue;
135→
136→      const rounded = roundToInterval(point.timestamp);
137→      if (seen.has(rounded)) continue;
138→      seen.add(rounded);
139→
140→      if (!snapshotMap.has(rounded)) snapshotMap.set(rounded, []);
141→      snapshotMap.get(rounded)!.push({
142→        username,
143→        rating: point.rating,
144→        position: point.position,
145→      });
146→    }
147→  }
148→
149→  const sortedTimes = [...snapshotMap.keys()].sort();
150→  const totalEntries = sortedTimes.reduce(
151→    (s, t) => s + snapshotMap.get(t)!.length,
152→    0
153→  );
154→  console.log(
155→    `${sortedTimes.length} snapshots, ${totalEntries} total entries to import`
156→  );
157→
158→  // 4. Load existing snapshots (to reuse IDs and skip already-populated ones)
159→  const existingResult = await d1Query(
160→    "SELECT id, fetched_at FROM snapshots WHERE season_id = ?",
161→    [SEASON_ID]
162→  );
163→  const existingSnapshots = new Map<string, number>(
164→    (existingResult as any).result[0].results.map(
165→      (r: { id: number; fetched_at: string }) => [r.fetched_at, r.id]
166→    )
167→  );
168→  console.log(`${existingSnapshots.size} existing snapshots in DB`);
169→
170→  // 5. Check which existing snapshots already have entries (to skip them)
171→  console.log("Checking existing entry counts...");
172→  const entryCountResult = await d1Query(
173→    `SELECT snapshot_id, COUNT(*) as cnt FROM entries
174→     WHERE snapshot_id IN (SELECT id FROM snapshots WHERE season_id = ?)
175→     GROUP BY snapshot_id`,
176→    [SEASON_ID]
177→  );
178→  const existingEntryCounts = new Map<number, number>(
179→    (entryCountResult as any).result[0].results.map(
180→      (r: { snapshot_id: number; cnt: number }) => [r.snapshot_id, r.cnt]
181→    )
182→  );
183→
184→  // 6. Insert snapshots and entries
185→  let processedSnapshots = 0;
186→  let skippedSnapshots = 0;
187→  let insertedEntries = 0;
188→
189→  for (const time of sortedTimes) {
190→    const entries = snapshotMap.get(time)!;
191→
192→    // Find or create snapshot
193→    let snapshotId = existingSnapshots.get(time);
194→    if (snapshotId == null) {
195→      const snapResult = await d1Query(
196→        `INSERT INTO snapshots (season_id, fetched_at, total_entries) VALUES (?, ?, ?) RETURNING id`,
197→        [SEASON_ID, time, entries.length]
198→      );
199→      snapshotId = (snapResult as any).result[0].results[0].id;
200→    } else {
201→      // Update total_entries if it was 0 (old pengx17-only import)
202→      await d1Query(
203→        `UPDATE snapshots SET total_entries = MAX(total_entries, ?) WHERE id = ?`,
204→        [entries.length, snapshotId]
205→      );
206→    }
207→
208→    // Skip if this snapshot already has enough entries
209→    const existingCount = existingEntryCounts.get(snapshotId) ?? 0;
210→    if (existingCount >= entries.length) {
211→      skippedSnapshots++;
212→      processedSnapshots++;
213→      if (processedSnapshots % 50 === 0) {
214→        console.log(
215→          `  Progress: ${processedSnapshots}/${sortedTimes.length} snapshots, ${insertedEntries} entries (${skippedSnapshots} skipped)`
216→        );
217→      }
218→      continue;
219→    }
220→
221→    // Insert entries in batches
222→    for (let i = 0; i < entries.length; i += BATCH_SIZE) {
223→      const batch = entries.slice(i, i + BATCH_SIZE);
224→      await d1InsertEntries(snapshotId, batch);
225→      insertedEntries += batch.length;
226→    }
227→
228→    processedSnapshots++;
229→    if (processedSnapshots % 50 === 0) {
230→      console.log(
231→        `  Progress: ${processedSnapshots}/${sortedTimes.length} snapshots, ${insertedEntries} entries (${skippedSnapshots} skipped)`
232→      );
233→    }
234→  }
235→
236→  console.log(
237→    `Done! Processed ${processedSnapshots} snapshots, ${insertedEntries} entries inserted, ${skippedSnapshots} skipped.`
238→  );
239→}
240→
241→main().catch((err) => {
242→  console.error(err);
243→  process.exit(1);
244→});
