  1→// scripts/backfill-derived-tables.ts
  2→// One-time script to backfill snapshot_metrics for existing snapshots
  3→// that were created before the derived tables existed.
  4→// Run via: npx tsx scripts/backfill-derived-tables.ts
  5→
  6→// ---------------------------------------------------------------------------
  7→// Configuration
  8→// ---------------------------------------------------------------------------
  9→
 10→const CF_API_TOKEN = requireEnv("CLOUDFLARE_API_TOKEN");
 11→const CF_ACCOUNT_ID = requireEnv("CLOUDFLARE_ACCOUNT_ID");
 12→const D1_DATABASE_ID = requireEnv("D1_DATABASE_ID");
 13→
 14→const D1_API_URL = `https://api.cloudflare.com/client/v4/accounts/${CF_ACCOUNT_ID}/d1/database/${D1_DATABASE_ID}/query`;
 15→
 16→interface D1Response<T = unknown> {
 17→  success: boolean;
 18→  errors: Array<{ code: number; message: string }>;
 19→  result: Array<{
 20→    success: boolean;
 21→    results: T[];
 22→    meta: Record<string, unknown>;
 23→  }>;
 24→}
 25→
 26→function requireEnv(name: string): string {
 27→  const value = process.env[name];
 28→  if (!value) throw new Error(`Missing: ${name}`);
 29→  return value;
 30→}
 31→
 32→function log(msg: string) {
 33→  console.log(`[${new Date().toISOString()}] ${msg}`);
 34→}
 35→
 36→async function queryD1<T = unknown>(sql: string, params?: unknown[]): Promise<T[]> {
 37→  const res = await fetch(D1_API_URL, {
 38→    method: "POST",
 39→    headers: {
 40→      Authorization: `Bearer ${CF_API_TOKEN}`,
 41→      "Content-Type": "application/json",
 42→    },
 43→    body: JSON.stringify({ sql, params }),
 44→  });
 45→
 46→  if (!res.ok) {
 47→    const text = await res.text();
 48→    throw new Error(`D1 API error (${res.status}): ${text}`);
 49→  }
 50→
 51→  const json = (await res.json()) as D1Response<T>;
 52→  if (!json.success) throw new Error(`D1 query failed: ${JSON.stringify(json.errors)}`);
 53→  return json.result[0]?.results ?? [];
 54→}
 55→
 56→// ---------------------------------------------------------------------------
 57→// Backfill snapshot_metrics
 58→// ---------------------------------------------------------------------------
 59→
 60→async function backfillMetrics(): Promise<void> {
 61→  // Find snapshots missing metrics
 62→  const missing = await queryD1<{ id: number }>(
 63→    `SELECT s.id FROM snapshots s
 64→     LEFT JOIN snapshot_metrics m ON m.snapshot_id = s.id
 65→     WHERE m.snapshot_id IS NULL AND s.total_entries > 1
 66→     ORDER BY s.id ASC`
 67→  );
 68→
 69→  log(`Found ${missing.length} snapshots missing metrics.`);
 70→
 71→  for (let i = 0; i < missing.length; i++) {
 72→    const sid = missing[i].id;
 73→
 74→    await queryD1(
 75→      `INSERT OR IGNORE INTO snapshot_metrics (snapshot_id, top1_rating, top10_rating, top100_rating, top1000_rating)
 76→       SELECT ?,
 77→         (SELECT rating FROM entries WHERE snapshot_id = ? AND position = 1),
 78→         (SELECT rating FROM entries WHERE snapshot_id = ? AND position <= 10 ORDER BY position DESC LIMIT 1),
 79→         (SELECT rating FROM entries WHERE snapshot_id = ? AND position <= 100 ORDER BY position DESC LIMIT 1),
 80→         (SELECT rating FROM entries WHERE snapshot_id = ? AND position <= 1000 ORDER BY position DESC LIMIT 1)`,
 81→      [sid, sid, sid, sid, sid]
 82→    );
 83→
 84→    if ((i + 1) % 50 === 0 || i === missing.length - 1) {
 85→      log(`  Metrics: ${i + 1}/${missing.length}`);
 86→    }
 87→  }
 88→
 89→  log("Metrics backfill complete.");
 90→}
 91→
 92→// ---------------------------------------------------------------------------
 93→// Main
 94→// ---------------------------------------------------------------------------
 95→
 96→async function main() {
 97→  log("=== Backfill Derived Tables Start ===");
 98→  await backfillMetrics();
 99→  log("=== Backfill Complete ===");
100→}
101→
102→main().catch((err) => {
103→  console.error("Fatal:", err);
104→  process.exit(1);
